module adder_8bit
(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);

    wire [6:0] carry;
    wire [7:0] s;
    assign s[0] = a[0] ^ b[0] ^ cin;
    assign carry[0] = (a[0] & b[0]) | (b[0] & cin) | (cin & a[0]);
    assign s[1] = a[1] ^ b[1] ^ carry[0];
    assign carry[1] = (a[1] & b[1]) | (b[1] & carry[0]) | (carry[0] & a[1]);
    assign s[2] = a[2] ^ b[2] ^ carry[1];
    assign carry[2] = (a[2] & b[2]) | (b[2] & carry[1]) | (carry[1] & a[2]);
    assign s[3] = a[3] ^ b[3] ^ carry[2];
    assign carry[3] = (a[3] & b[3]) | (b[3] & carry[2]) | (carry[2] & a[3]);
    assign s[4] = a[4] ^ b[4] ^ carry[3];
    assign carry[4] = (a[4] & b[4]) | (b[4] & carry[3]) | (carry[3] & a[4]);
    assign s[5] = a[5] ^ b[5] ^ carry[4];
    assign carry[5] = (a[5] & b[5]) | (b[5] & carry[4]) | (carry[4] & a[5]);
    assign s[6] = a[6] ^ b[6] ^ carry[5];
    assign carry[6] = (a[6] & b[6]) | (b[6] & carry[5]) | (carry[5] & a[6]);
    assign s[7] = a[7] ^ b[7] ^ carry[6];
    assign cout = (a[7] & b[7]) | (b[7] & carry[6]) | (carry[6] & a[7]);
    assign sum = s;
endmodule
